import { useState } from "react";

const LOGO_URI = "data:image/png;base64,";

// ============================================================
// DONUT CHART COMPONENT
// ============================================================
const SYMBOLS = ["🌱", "🔥", "⭐", "🦋", "🌊", "🧠", "💎", "🌙", "🎯", "🦅", "🌻", "⚡"];

const DonutChart = ({ percentage, size = 90, strokeWidth = 10 }) => {
  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (percentage / 100) * circumference;
  const center = size / 2;

  const getColor = (pct) => {
    if (pct >= 75) return "#4A7C6F";
    if (pct >= 40) return "#D4A373";
    return "#C4887A";
  };

  return (
    <div style={{ position: "relative", width: size, height: size, flexShrink: 0 }}>
      <svg width={size} height={size} style={{ transform: "rotate(-90deg)" }}>
        <circle cx={center} cy={center} r={radius} fill="none" stroke="#E8E4DF" strokeWidth={strokeWidth} />
        <circle
          cx={center} cy={center} r={radius} fill="none"
          stroke={getColor(percentage)} strokeWidth={strokeWidth}
          strokeDasharray={circumference} strokeDashoffset={offset}
          strokeLinecap="round"
          style={{ transition: "stroke-dashoffset 0.6s ease, stroke 0.3s ease" }}
        />
      </svg>
      <div style={{
        position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center",
        fontFamily: "'DM Sans', sans-serif", fontSize: 16, fontWeight: 700, color: "#3D3529"
      }}>
        {Math.round(percentage)}%
      </div>
    </div>
  );
};

// ============================================================
// EDITABLE TEXT COMPONENT
// ============================================================
const EditableText = ({ value, onChange, placeholder, style = {}, multiline = false }) => {
  const Tag = multiline ? "textarea" : "input";
  return (
    <Tag
      value={value}
      onChange={(e) => onChange(e.target.value)}
      placeholder={placeholder}
      style={{
        background: "transparent", border: "none", outline: "none", width: "100%",
        fontFamily: "'DM Sans', sans-serif", fontSize: 14, color: "#3D3529",
        resize: multiline ? "vertical" : "none",
        minHeight: multiline ? 60 : "auto",
        padding: "4px 0",
        ...style,
      }}
    />
  );
};

// ============================================================
// ACTION ITEM ROW
// ============================================================
const ActionItem = ({ action, onUpdate, onDelete }) => {
  return (
    <div style={{
      padding: "12px 0",
      borderBottom: "1px solid #F0ECE6",
    }}>
      <div style={{ display: "flex", alignItems: "flex-start", gap: 10 }}>
        <button
          onClick={() => onUpdate({ ...action, done: !action.done })}
          style={{
            width: 22, height: 22, borderRadius: 6, border: `2px solid ${action.done ? "#4A7C6F" : "#C4BAA8"}`,
            background: action.done ? "#4A7C6F" : "transparent", cursor: "pointer",
            display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, padding: 0,
            marginTop: 2,
          }}
        >
          {action.done && (
            <svg width="12" height="12" viewBox="0 0 12 12" fill="none">
              <path d="M2.5 6L5 8.5L9.5 3.5" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          )}
        </button>
        <div style={{ flex: 1, minWidth: 0 }}>
          <EditableText
            value={action.text}
            onChange={(text) => onUpdate({ ...action, text })}
            placeholder="Action step..."
            style={{
              textDecoration: action.done ? "line-through" : "none",
              color: action.done ? "#A89F91" : "#3D3529",
              width: "100%",
            }}
          />
          <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginTop: 6 }}>
            <input
              type="date"
              value={action.dueDate || ""}
              onChange={(e) => onUpdate({ ...action, dueDate: e.target.value })}
              style={{
                fontFamily: "'DM Sans', sans-serif", fontSize: 12, color: "#8A8070",
                border: "1px solid #E8E4DF", borderRadius: 6, padding: "3px 6px",
                background: "#FDFCFA", width: 120,
              }}
            />
            <select
              value={action.status || "todo"}
              onChange={(e) => onUpdate({ ...action, status: e.target.value })}
              style={{
                fontFamily: "'DM Sans', sans-serif", fontSize: 12,
                border: "1px solid #E8E4DF", borderRadius: 6, padding: "3px 8px",
                background: action.status === "done" ? "#E8F5E8" : action.status === "in-progress" ? "#FFF3E0" : "#FDFCFA",
                color: "#3D3529", width: 100,
              }}
            >
              <option value="todo">To Do</option>
              <option value="in-progress">In Progress</option>
              <option value="done">Done</option>
            </select>
          </div>
        </div>
        <button
          onClick={onDelete}
          style={{
            background: "none", border: "none", cursor: "pointer", padding: 4,
            color: "#C4BAA8", fontSize: 16, lineHeight: 1, flexShrink: 0,
          }}
          title="Remove"
        >×</button>
      </div>
    </div>
  );
};

// ============================================================
// GOAL CARD COMPONENT
// ============================================================
const GoalCard = ({ goal, onUpdate, onDelete }) => {
  const [expanded, setExpanded] = useState(false);

  const totalActions = goal.actions.length;
  const doneActions = goal.actions.filter((a) => a.done).length;
  const percentage = totalActions === 0 ? 0 : (doneActions / totalActions) * 100;

  const addAction = () => {
    onUpdate({
      ...goal,
      actions: [...goal.actions, { id: Date.now(), text: "", done: false, dueDate: "", status: "todo" }],
    });
  };

  const updateAction = (idx, updated) => {
    const newActions = [...goal.actions];
    newActions[idx] = updated;
    if (updated.done) updated.status = "done";
    if (!updated.done && updated.status === "done") updated.status = "in-progress";
    onUpdate({ ...goal, actions: newActions });
  };

  const deleteAction = (idx) => {
    onUpdate({ ...goal, actions: goal.actions.filter((_, i) => i !== idx) });
  };

  return (
    <div style={{
      background: "#FFFFFF", borderRadius: 16, border: "1px solid #E8E4DF",
      overflow: "hidden", boxShadow: "0 1px 3px rgba(61,53,41,0.04)",
    }}>
      {/* Header */}
      <div
        onClick={() => setExpanded(!expanded)}
        style={{
          display: "flex", alignItems: "center", justifyContent: "space-between",
          padding: "20px 24px", cursor: "pointer", gap: 16,
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 16, flex: 1, minWidth: 0 }}>
          <div style={{
            width: 8, height: 40, borderRadius: 4, flexShrink: 0,
            background: percentage >= 75 ? "#4A7C6F" : percentage >= 40 ? "#D4A373" : "#C4887A",
          }} />
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{
              fontFamily: "'DM Sans', sans-serif", fontSize: 17, fontWeight: 700,
              color: "#3D3529", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
            }}>
              {goal.title || "Untitled Goal"}
            </div>
            <div style={{
              fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: "#8A8070", marginTop: 2,
            }}>
              {doneActions}/{totalActions} actions complete
            </div>
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
          <DonutChart percentage={percentage} size={56} strokeWidth={7} />
          <svg
            width="20" height="20" viewBox="0 0 20 20" fill="none"
            style={{ transform: expanded ? "rotate(180deg)" : "rotate(0deg)", transition: "transform 0.2s ease", flexShrink: 0 }}
          >
            <path d="M5 7.5L10 12.5L15 7.5" stroke="#8A8070" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
        </div>
      </div>

      {/* Expanded Content */}
      {expanded && (
        <div style={{ padding: "0 24px 24px", borderTop: "1px solid #F0ECE6" }}>
          {/* Goal Title & Why */}
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginTop: 20 }}>
            <div>
              <label style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, fontWeight: 700, color: "#8A8070", textTransform: "uppercase", letterSpacing: 1 }}>
                Goal
              </label>
              <EditableText
                value={goal.title}
                onChange={(title) => onUpdate({ ...goal, title })}
                placeholder="What's the goal?"
                style={{ fontSize: 15, fontWeight: 600 }}
              />
            </div>
            <div>
              <label style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, fontWeight: 700, color: "#8A8070", textTransform: "uppercase", letterSpacing: 1 }}>
                Why This Matters
              </label>
              <EditableText
                value={goal.why}
                onChange={(why) => onUpdate({ ...goal, why })}
                placeholder="Connect it to the North Star..."
                style={{ fontSize: 14 }}
              />
            </div>
          </div>

          {/* Challenges */}
          <div style={{ marginTop: 16 }}>
            <label style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, fontWeight: 700, color: "#8A8070", textTransform: "uppercase", letterSpacing: 1 }}>
              Challenges
            </label>
            <EditableText
              value={goal.challenges}
              onChange={(challenges) => onUpdate({ ...goal, challenges })}
              placeholder="What obstacles are in the way?"
              style={{ fontSize: 14 }}
            />
          </div>

          {/* Action Steps */}
          <div style={{ marginTop: 20 }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 8 }}>
              <label style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, fontWeight: 700, color: "#8A8070", textTransform: "uppercase", letterSpacing: 1 }}>
                Action Steps
              </label>
              <button
                onClick={addAction}
                style={{
                  fontFamily: "'DM Sans', sans-serif", fontSize: 12, fontWeight: 600,
                  color: "#4A7C6F", background: "#E8F5F0", border: "none", borderRadius: 8,
                  padding: "5px 12px", cursor: "pointer",
                }}
              >
                + Add Step
              </button>
            </div>
            {goal.actions.length === 0 ? (
              <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: "#B5AD9E", padding: "12px 0", fontStyle: "italic" }}>
                No action steps yet. Click "+ Add Step" to get started.
              </div>
            ) : (
              goal.actions.map((action, idx) => (
                <ActionItem
                  key={action.id}
                  action={action}
                  onUpdate={(updated) => updateAction(idx, updated)}
                  onDelete={() => deleteAction(idx)}
                />
              ))
            )}
          </div>

          {/* Goal Notes */}
          <div style={{ marginTop: 20 }}>
            <label style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, fontWeight: 700, color: "#8A8070", textTransform: "uppercase", letterSpacing: 1 }}>
              Goal Notes
            </label>
            <EditableText
              value={goal.notes}
              onChange={(notes) => onUpdate({ ...goal, notes })}
              placeholder="Observations, context, session insights for this goal..."
              multiline
              style={{ fontSize: 13, background: "#FAF8F5", borderRadius: 8, padding: 12, marginTop: 6, border: "1px solid #F0ECE6" }}
            />
          </div>

          {/* Delete Goal */}
          <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 16 }}>
            <button
              onClick={onDelete}
              style={{
                fontFamily: "'DM Sans', sans-serif", fontSize: 12, color: "#C4887A",
                background: "none", border: "1px solid #E8E4DF", borderRadius: 8,
                padding: "5px 14px", cursor: "pointer",
              }}
            >
              Remove Goal
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

